-- HISTORICAL ERAS (10 records)
-- ============================================================
INSERT INTO historical_eras (slug, name, description, start_year, end_year, key_characteristics, is_featured) VALUES
('prehistoric-period', 'Prehistoric Period', 'Stone Age settlements, cave paintings, and early Himalayan civilization in Nepal. Evidence of human habitation dating back to 30,000 years.', -10000, -600, 'Stone tools, cave paintings at Armala and Khuibari, early hunter-gatherer societies, Tharu and other indigenous origins', true),
('kirat-period', 'Kirat Period', 'First organized kingdoms in Nepal. The Kirat dynasty ruled for approximately 800 years with 29 kings. Linked to Mahabharata legends.', -600, 300, 'First political confederation, 29 Kirat kings, Yalamber legendary warrior, eastern Nepal origin, Mundhum oral tradition', true),
('licchavi-period', 'Licchavi Period', 'Golden age of Nepal. Stone inscriptions, Hindu-Buddhist synthesis, trade expansion, and remarkable art/architecture.', 400, 879, 'Stone inscriptions, Hindu-Buddhist synthesis, Manadeva I, Amshuverma, Bhrikuti, Araniko, Nepal Sambat era begins', true),
('thakuri-period', 'Thakuri Period', 'Post-Licchavi era. Kasthamandap wooden pavilion built, Indra Jatra festival started, Nepal Era calendar initiated.', 879, 1120, 'Kasthamandap origin of Kathmandu name, Indra Jatra festival, Nepal Sambat calendar, Gunakama Deva', true),
('malla-period', 'Malla Period', 'Art and architecture golden age. Three rival kingdoms, magnificent Durbar Squares, cultural zenith of Newari civilization.', 1200, 1769, 'Durbar Squares, 3 rival kingdoms, Pratap Malla, Nyatapola Temple, cultural golden age, caste codification', true),
('gorkha-unification', 'Gorkha Unification', 'Prithvi Narayan Shah unified 50+ kingdoms into modern Nepal. Conquered Kathmandu Valley during Indra Jatra festival.', 1743, 1816, 'Prithvi Narayan Shah, valley conquest, Dibya Upadesh, Battle of Kirtipur, Anglo-Nepalese War, Treaty of Sugauli', true),
('rana-oligarchy', 'Rana Oligarchy', '104 years of hereditary Rana Prime Ministers. Shah kings reduced to figureheads. Nepal isolated from the world.', 1846, 1951, 'Kot Massacre, hereditary PMs, isolation, abolition of Sati and Slavery, Singha Durbar, modernization begins', true),
('panchayat-era', 'Panchayat Era', 'Partyless system under absolute monarchy. Mahendra''s coup dissolved parliament. 30 years of centralized authoritarian rule.', 1960, 1990, 'Partyless pyramid, Mahendra Highway, malaria eradication, 1980 referendum, political repression', true),
('constitutional-monarchy-civil-war', 'Constitutional Monarchy & Civil War', 'Jana Andolan I restored multiparty democracy. Royal massacre killed King Birendra. Maoist insurgency lasted 10 years.', 1990, 2008, 'Jana Andolan I, multiparty democracy, Maoist civil war, Royal Massacre, Jana Andolan II, monarchy abolished', true),
('federal-democratic-republic', 'Federal Democratic Republic', 'Nepal became a federal democratic republic. 2015 constitution. Gen Z revolution of September 2025 transformed politics.', 2008, NULL, 'Republic declared, 7 provinces, 2015 constitution, Gen Z revolution 2025, Balen Shah era, youth awakening', true);

