INSERT INTO historical_figures (slug, name, description, figure_type, birth_year, death_year, birth_place, known_for, key_achievements, dynasty_affiliation, era_name, is_featured) VALUES
-- Ancient & Medieval (10)
('yalamber', 'Yalamber', 'Legendary first Kirat king and warrior. Said to have participated in the Mahabharata war from the Nepali side. Founded the Kirat dynasty.', 'KING', -600, -520, 'Eastern Nepal', 'First Kirat king, legendary warrior, Mahabharata connection', 'First major political confederation in Nepal, founded 29-king dynasty', 'Kirat Dynasty', 'Kirat Period', true),
('manadeva-i', 'Manadeva I', 'Earliest historically verified king of Nepal. His stone inscription at Changu Narayan (464 CE) is the oldest surviving inscription in Nepal.', 'KING', 420, 464, 'Kathmandu Valley', 'Earliest verified king, Changu Narayan inscription', 'Established Licchavi rule, stone inscription legacy', 'Licchavi Dynasty', 'Licchavi Period', true),
('amshuverma', 'Amshuverma', 'Greatest Licchavi king. Expanded trade routes to Tibet and India. Married his daughter Bhrikuti to Tibetan king Songtsen Gampo.', 'KING', 580, 621, 'Kathmandu Valley', 'Trade expansion, Bhrikuti marriage, cultural golden age', 'Opened trade routes, cultural diplomacy, Licchavi zenith', 'Licchavi Dynasty', 'Licchavi Period', true),
('bhrikuti', 'Bhrikuti', 'Nepali princess married to Tibetan king Songtsen Gampo. Spread Buddhism to Tibet. Cultural bridge between Nepal and Tibet.', 'SCHOLAR', 600, 650, 'Kathmandu Valley', 'Spread Buddhism to Tibet, cultural bridge', 'Marriage alliance, Buddhist mission to Tibet', 'Licchavi Dynasty', 'Licchavi Period', true),
('araniko', 'Araniko', 'Nepali architect sent to Beijing by Kublai Khan. Built the White Stupa (White Pagoda) in Beijing. Bridged Nepali and Chinese cultures.', 'SCHOLAR', 1245, 1306, 'Kathmandu Valley', 'White Stupa in Beijing, cultural ambassador', 'Built White Stupa, bridged cultures, architectural genius', 'Malla Dynasty (Kantipur)', 'Malla Period', false),
('gunakama-deva', 'Gunakama Deva', 'Thakuri king who built the Kasthamandap wooden pavilion, giving Kathmandu its name (Kastha=wood, Mandap=pavilion).', 'KING', 920, 994, 'Kathmandu Valley', 'Built Kasthamandap, origin of Kathmandu name', 'Kasthamandap construction, city naming', 'Thakuri Dynasty', 'Thakuri Period', true),
('sankhadhar-sakhwa', 'Sankhadhar Sakhwa', 'Beloved folk hero who started the Nepal Sambat era in 879 CE. Freed debtors and helped the poor. Celebrated annually.', 'SCHOLAR', 750, 820, 'Kathmandu Valley', 'Started Nepal Sambat era, freed debtors', 'Created Nepal Sambat calendar, freed debtors', 'Thakuri Dynasty', 'Thakuri Period', true),
('jayasthiti-malla', 'Jayasthiti Malla', 'Malla king who codified the Hindu caste system in Nepal, classifying 64 castes. Unified Kathmandu Valley temporarily.', 'KING', 1350, 1395, 'Kathmandu Valley', 'Caste codification, 64 castes classified', 'Formalized caste system, temporary valley unification', 'Malla Dynasty (Kantipur)', 'Malla Period', false),
('yakshamalla', 'Yakshamalla', 'Last Malla king to unite all three kingdoms of Kathmandu Valley. Cultural patron and builder.', 'KING', 1420, 1482, 'Kathmandu Valley', 'Last king to unite all three kingdoms', 'Valley unification, cultural patronage', 'Malla Dynasty (Kantipur)', 'Malla Period', false),
('bhupatindra-malla', 'Bhupatindra Malla', 'Builder of the Nyatapola Temple in Bhaktapur, the tallest pagoda in Nepal. Masterpiece of Nepali architecture.', 'KING', 1653, 1705, 'Bhaktapur', 'Nyatapola Temple builder', 'Built Nyatapola Temple, architectural masterpiece', 'Malla Dynasty (Bhaktapur)', 'Malla Period', true),

-- Shah Dynasty & Unification (12)
('dravya-shah', 'Dravya Shah', 'Founded Gorkha Kingdom in 1559 by defeating local Magar king Dalsur Ghale with the help of 6 accomplices.', 'KING', 1530, 1570, 'Lamjung', 'Founded Gorkha Kingdom', 'Conquered Gorkha, established dynasty', 'Shah Dynasty (Gorkha)', 'Gorkha Unification', false),
('ram-shah', 'Ram Shah', 'Called Ram Shah The Just. Created Nepal''s first judicial system. Famous proverb: If you seek justice, go to Gorkha.', 'KING', 1580, 1636, 'Gorkha', 'First judicial system, justice proverb', 'Created justice system, standardized weights and measures', 'Shah Dynasty (Gorkha)', 'Gorkha Unification', false),
('nar-bhupal-shah', 'Nar Bhupal Shah', 'Father of Prithvi Narayan Shah. Lost the battle of Nuwakot which motivated his son to begin unification.', 'KING', 1697, 1743, 'Gorkha', 'Father of Prithvi Narayan Shah', 'Lost Nuwakot battle, inspired unification movement', 'Shah Dynasty (Gorkha)', 'Gorkha Unification', false),
('prithvi-narayan-shah', 'Prithvi Narayan Shah', 'Founder of modern Nepal. Unified over 50 small kingdoms into one nation. Wrote Dibya Upadesh political treatise. Nepal is a garden of 4 castes and 36 ethnic groups.', 'KING', 1723, 1775, 'Gorkha', 'Founder of modern Nepal, unified 50+ kingdoms', 'Unified Nepal, wrote Dibya Upadesh, established capital at Kathmandu', 'Shah Dynasty (Nepal)', 'Gorkha Unification', true),
('abhaya-rajya-lakshmi', 'Abhaya Rajya Lakshmi', 'Wife of Prithvi Narayan Shah. Managed Kathmandu Valley campaigns while Prithvi Narayan was conquering.', 'DIPLOMAT', 1740, 1800, 'Kathmandu Valley', 'Managed valley campaigns', 'Political management during unification', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('pratap-singh-shah', 'Pratap Singh Shah', 'Son of Prithvi Narayan Shah. Died young at 26. Maintained father''s policies during brief reign.', 'KING', 1751, 1777, 'Kathmandu', 'Maintained unification policies', 'Continued father''s work, brief reign', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('rana-bahadur-shah', 'Rana Bahadur Shah', 'Became king as infant. First Shah king to voluntarily abdicate. Married Brahman widow. Murdered by his own brother in 1806.', 'KING', 1775, 1806, 'Kathmandu', 'Voluntary abdication, married Brahman widow', 'Abdicated throne, progressive marriage', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('girvan-yuddha-bikram-shah', 'Girvan Yuddha Bikram Shah', 'Child king who lost one-third of Nepal in the Treaty of Sugauli during the Anglo-Nepalese War. Died at just 19.', 'KING', 1797, 1816, 'Kathmandu', 'Anglo-Nepalese War, Treaty of Sugauli', 'Lost territory in Sugauli Treaty', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('balbhadra-kunwar', 'Balbhadra Kunwar', 'Led 600 Nepalis against 30,000 British at Battle of Nalapani. Legendary last stand. Symbol of Nepali courage.', 'WARRIOR', 1789, 1823, 'Gorkha', 'Battle of Nalapani last stand', 'Legendary defense with 600 vs 30,000', 'Shah Dynasty (Nepal)', 'Gorkha Unification', true),
('amar-singh-thapa', 'Amar Singh Thapa', 'Called Singh of Nepal. Commanded western front in Anglo-Nepalese War. One of Nepal''s greatest warriors.', 'WARRIOR', 1759, 1816, 'Western Nepal', 'Singh of Nepal, western front commander', 'Defended western Nepal, military genius', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('bhimsen-thapa', 'Bhimsen Thapa', 'First PM of Nepal. Modernizer who tried to reform the military and state. Eventually imprisoned and died in captivity.', 'DIPLOMAT', 1775, 1839, 'Kathmandu', 'First PM of Nepal, modernizer', 'Military reform, diplomatic efforts', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),
('mathabar-singh-thapa', 'Mathabar Singh Thapa', 'PM before the Kot Massacre. Assassinated by Jung Bahadur Rana''s allies in 1845.', 'DIPLOMAT', 1806, 1845, 'Kathmandu', 'PM before Kot Massacre', 'Last PM before Rana takeover', 'Shah Dynasty (Nepal)', 'Gorkha Unification', false),

-- Rana Dynasty (11)
('jung-bahadur-rana', 'Jung Bahadur Rana', 'Founded the Rana dynasty after the Kot Massacre of 1846. First Nepalese leader to visit Europe. Introduced the Muluki Ain legal code.', 'KING', 1817, 1877, 'Kathmandu', 'Founded Rana dynasty, Kot Massacre, visited Europe', 'Established hereditary premiership, Muluki Ain legal code', 'Rana Dynasty', 'Rana Oligarchy', true),
('bam-bahadur-kunwar', 'Bam Bahadur Kunwar', 'Brother of Jung Bahadur Rana. Briefly served as PM for 11 months before Jung Bahadur returned to power.', 'KING', 1826, 1858, 'Kathmandu', 'Brief 11-month rule', 'Transitional rule, administrative continuity', 'Rana Dynasty', 'Rana Oligarchy', false),
('ranodip-singh-kunwar', 'Ranodip Singh Kunwar', 'Jung Bahadur''s brother. Maintained stability for 8 years. Assassinated in the Shumsher family coup of 1885.', 'KING', 1825, 1885, 'Kathmandu', 'Assassinated in Shumsher coup', 'Maintained stability, victim of coup', 'Rana Dynasty', 'Rana Oligarchy', false),
('bir-shumsher-rana', 'Bir Shumsher Rana', 'Took power after assassinating Ranodip Singh. Founded Bir Hospital. Established anti-corruption system.', 'KING', 1852, 1901, 'Kathmandu', 'Founded Bir Hospital, anti-corruption', 'Hospital establishment, anti-corruption measures', 'Rana Dynasty', 'Rana Oligarchy', false),
('dev-shumsher-rana', 'Dev Shumsher Rana', 'Reformist PM who ruled for only 114 days. Founded Gorkhapatra newspaper. Issued first slavery abolition proclamation. Deposed by brother Chandra.', 'REFORM', 1862, 1914, 'Kathmandu', 'Founded Gorkhapatra, first slavery abolition', 'Newspaper founding, slavery proclamation', 'Rana Dynasty', 'Rana Oligarchy', true),
('chandra-shumsher-rana', 'Chandra Shumsher Rana', 'Greatest reformer Rana PM. Abolished Sati (1920), abolished slavery (1924), built Singha Durbar, founded Tri-Chandra College.', 'DIPLOMAT', 1863, 1929, 'Kathmandu', 'Abolished Sati and slavery, built Singha Durbar', 'Abolished Sati 1920, slavery 1924, first college, Singha Durbar', 'Rana Dynasty', 'Rana Oligarchy', true),
('bhim-shumsher-rana', 'Bhim Shumsher Rana', 'Focused on palace construction during his 3-year rule. Died in office.', 'KING', 1865, 1932, 'Kathmandu', 'Palace construction', 'Architectural projects', 'Rana Dynasty', 'Rana Oligarchy', false),
('juddha-shumsher-rana', 'Juddha Shumsher Rana', 'Rebuilt Dharahara after 1934 earthquake. Established Nepal Bank. Supported Britain in WWII with 250,000 troops. Voluntarily abdicated.', 'KING', 1875, 1952, 'Kathmandu', 'Rebuilt Dharahara, Nepal Bank, WWII support', 'Banking, industrialization, 250,000 troops in WWII', 'Rana Dynasty', 'Rana Oligarchy', true),
('padma-shumsher-rana', 'Padma Shumsher Rana', 'Promulgated Nepal''s first written constitution in 1948. Established girls'' schools. Progressive but resigned under family pressure.', 'REFORM', 1882, 1961, 'Kathmandu', 'First constitution of Nepal', 'First written constitution, girls schools, US relations', 'Rana Dynasty', 'Rana Oligarchy', true),
('mohan-shumsher-rana', 'Mohan Shumsher Rana', 'Last Rana PM. Signed the Delhi Accord ending 104 years of Rana rule. Stepped down in November 1951.', 'KING', 1885, 1967, 'Kathmandu', 'Last Rana PM, Delhi Accord', 'Ended Rana rule, signed peace accord', 'Rana Dynasty', 'Rana Oligarchy', true),

-- Democracy Activists (12)
('bhanubhakta-acharya', 'Bhanubhakta Acharya', 'Called Adikavi (first poet). Translated the Ramayana into Nepali, making it accessible to common people.', 'SCHOLAR', 1814, 1868, 'Tanahu', 'Adikavi, Ramayana translation', 'First Nepali poet, translated Ramayana', NULL, 'Constitutional Monarchy & Civil War', false),
('laxmi-prasad-devkota', 'Laxmi Prasad Devkota', 'Called Mahakavi (great poet). Wrote Muna Madan and other masterpieces. Greatest poet in Nepali literature.', 'SCHOLAR', 1909, 1959, 'Kathmandu', 'Mahakavi, Muna Madan', 'Literary genius, Muna Madan, national treasure', NULL, 'Constitutional Monarchy & Civil War', true),
('tribhuvan-bir-bikram-shah', 'Tribhuvan Bir Bikram Shah', 'Father of the Nation. Dramatically escaped to Indian Embassy in 1950, ending 104 years of Rana rule. Restored democracy.', 'KING', 1906, 1955, 'Kathmandu', 'Father of the Nation, ended Rana rule', 'Fled to Indian Embassy, restored monarchy, ended Rana oligarchy', 'Shah Dynasty (Nepal)', 'Rana Oligarchy', true),
('tanka-prasad-acharya', 'Tanka Prasad Acharya', 'Founder of Nepal Praja Parishad, first political party. Imprisoned by Ranas. First republican-minded political leader.', 'ACTIVIST', 1912, 1992, 'Kathmandu', 'Nepal Praja Parishad founder', 'Founded first political party, anti-Rana activism', NULL, 'Rana Oligarchy', false),
('bp-koirala', 'BP Koirala', 'First democratically elected PM of Nepal (1959). Nepali Congress founder. Imprisoned multiple times. Democratic icon.', 'ACTIVIST', 1914, 1982, 'Varanasi, India', 'First elected PM, Nepali Congress founder', 'Won 1959 elections, land reform, democratic leadership', 'Nepali Congress', 'Constitutional Monarchy & Civil War', true),
('subarna-shamsher-rana', 'Subarna Shamsher Rana', 'Rana prince who joined the democracy movement. Progressive reformer who challenged his own family.', 'REFORM', 1910, 1977, 'Kathmandu', 'Rana prince turned democrat', 'Crossed class lines for democracy', NULL, 'Constitutional Monarchy & Civil War', false),
('mahendra-bir-bikram-shah', 'Mahendra Bir Bikram Shah', 'King who staged the 1960 royal coup, dissolved parliament, and introduced the Panchayat system lasting 30 years.', 'KING', 1920, 1972, 'Kathmandu', '1960 coup, Panchayat system', 'Dissolved democracy, built Mahendra Highway, partyless system', 'Shah Dynasty (Nepal)', 'Panchayat Era', true),
('matrika-prasad-koirala', 'Matrika Prasad Koirala', 'First non-Rana PM in 104 years (1951). Served twice as PM. Moderate politician during transition.', 'DIPLOMAT', 1912, 2002, 'Kathmandu', 'First non-Rana PM', 'First democratic PM after Rana era', 'Nepali Congress', 'Constitutional Monarchy & Civil War', false),
('girija-prasad-koirala', 'Girija Prasad Koirala', 'PM 4 times. Led Jana Andolan II in 2006. Democratic icon who served across decades of Nepali politics.', 'ACTIVIST', 1925, 2010, 'Kathmandu', 'PM 4 times, Jana Andolan II leader', 'Multiple terms as PM, peace accord, democratic leadership', 'Nepali Congress', 'Constitutional Monarchy & Civil War', true),
('krishna-prasad-bhattarai', 'Krishna Prasad Bhattarai', 'Interim PM after Jana Andolan I (1990). Known as Bhatter Dai. Respected elder statesman.', 'ACTIVIST', 1924, 2011, 'Kathmandu', 'Interim PM 1990, Bhatter Dai', 'Transitional leadership, respected statesman', 'Nepali Congress', 'Constitutional Monarchy & Civil War', false),
('man-mohan-adhikari', 'Man Mohan Adhikari', 'First communist PM of Nepal (1994-95). Moderate left leader who worked within democratic framework.', 'ACTIVIST', 1920, 1999, 'Kathmandu', 'First communist PM', 'First communist PM, moderate governance', 'CPN (UML)', 'Constitutional Monarchy & Civil War', false),
('surya-bahadur-thapa', 'Surya Bahadur Thapa', 'PM 5 times across Panchayat and democracy eras. Lasted from 1960s to 2000s in Nepali politics.', 'DIPLOMAT', 1928, 2015, 'Dang', 'PM 5 times', 'Longest-serving political figure across eras', 'RPP', 'Panchayat Era', false),

