('malla-dynasty-lalitpur', 'Malla Dynasty (Lalitpur)', 'Patan Malla kingdom. Known for metal crafts, 35+ courtyards, Hiranya Varna Mahavihar.', (SELECT id FROM historical_eras WHERE slug='malla-period'), NULL, 1201, 1769, 'Lalitpur', 'Metal crafts, courtyards, architectural gems', 15, false),
('malla-dynasty-bhaktapur', 'Malla Dynasty (Bhaktapur)', 'Bhaktapur Malla kingdom. Nyatapola Temple, 55 Window Palace, Pottery Square.', (SELECT id FROM historical_eras WHERE slug='malla-period'), (SELECT id FROM historical_figures WHERE slug='bhupatindra-malla'), 1201, 1769, 'Bhaktapur', 'Nyatapola Temple, 55 Window Palace', 12, true),

