('shah-dynasty-gorkha', 'Shah Dynasty (Gorkha)', 'Gorkha principality for 210 years before unification. 10 kings from Dravya Shah to Prithvi Narayan Shah.', (SELECT id FROM historical_eras WHERE slug='gorkha-unification'), (SELECT id FROM historical_figures WHERE slug='dravya-shah'), 1559, 1768, 'Gorkha', 'Founded Gorkha, justice system, unification movement', 10, true),
